sql.where:
t.user_id = #{userId}
AND t.deleted_at IS NULL

    AND t.status = #{status}


    AND t.priority = #{priority}


    AND (
        t.title LIKE #{keywordLike} ESCAPE '\\'
        OR t.description LIKE #{keywordLike} ESCAPE '\\'
    )


    AND t.due_at >= #{dueFrom}


    AND t.due_at <= #{dueTo}
